INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת כניסה אלומיניום — צילינדר/מנעול לא תקני** — צילינדר המנעול בדלת הכניסה אינו עומד בתקן אבטחה — ללא הגנה מפני קידוח, פריצה, או bump key. או שבולט מעבר לרוזטה ביותר מ-3 מ"מ.. המלצה: להחליף את הצילינדר בצילינדר תקני בעל דרגת אבטחה מתאימה (לפחות 5 פינים, הגנת קידוח).. עלות משוערת: ₪200-₪600 (ליחידה)', '**דלת כניסה אלומיניום — צילינדר/מנעול לא תקני** — צילינדר המנעול בדלת הכניסה אינו עומד בתקן אבטחה — ללא הגנה מפני קידוח, פריצה, או bump key. או שבולט מעבר לרוזטה ביותר מ-3 מ"מ.. המלצה: להחליף את הצילינדר בצילינדר תקני בעל דרגת אבטחה מתאימה (לפחות 5 פינים, הגנת קידוח).. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 5514 — צילינדר בדלת כניסה חייב לעמוד בדרגת אבטחה מינימלית לפי ת"י 5514', 'ת"י 5514 — צילינדר בדלת כניסה חייב לעמוד בדרגת אבטחה מינימלית לפי ת"י 5514', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת אלומיניום — סוגר (Door Closer) חסר או לא מכוונן** — סוגר דלת (door closer) חסר בדלת שנדרש בה (דלת חדר מדרגות, דלת אש), או שהסוגר הקיים לא מכוונן — הדלת נטרקת או לא נסגרת עד הסוף.. המלצה: להתקין סוגר דלת מתאים לגודל ומשקל הדלת. אם קיים — לכוונן את מהירות הסגירה והנעילה (latch speed).. עלות משוערת: ₪300-₪800 (ליחידה)', '**דלת אלומיניום — סוגר (Door Closer) חסר או לא מכוונן** — סוגר דלת (door closer) חסר בדלת שנדרש בה (דלת חדר מדרגות, דלת אש), או שהסוגר הקיים לא מכוונן — הדלת נטרקת או לא נסגרת עד הסוף.. המלצה: להתקין סוגר דלת מתאים לגודל ומשקל הדלת. אם קיים — לכוונן את מהירות הסגירה והנעילה (latch speed).. עלות משוערת: ₪300-₪800 (ליחידה)', 'ת"י 1555 — דלתות בדרכי מילוט ודלתות אש חייבות בסוגר עצמי מאושר שמחזיר את הדלת לסגירה מלאה', 'ת"י 1555 — דלתות בדרכי מילוט ודלתות אש חייבות בסוגר עצמי מאושר שמחזיר את הדלת לסגירה מלאה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת אלומיניום — פער לא אחיד בין כנף למשקוף** — הרווח בין כנף הדלת למסגרת (משקוף ומזוזות) לא אחיד — גדול מדי בצד אחד וצר מהצד השני. מעיד על כנף שלא מכוונת, צירים שחוקים, או מסגרת מעוותת.. המלצה: לכוונן את הצירים להשגת רווח אחיד. אם הצירים שחוקים — להחליפם. במקרה של מסגרת מעוותת — ליישר ולעגן מחדש.. עלות משוערת: ₪150-₪500 (ליחידה)', '**דלת אלומיניום — פער לא אחיד בין כנף למשקוף** — הרווח בין כנף הדלת למסגרת (משקוף ומזוזות) לא אחיד — גדול מדי בצד אחד וצר מהצד השני. מעיד על כנף שלא מכוונת, צירים שחוקים, או מסגרת מעוותת.. המלצה: לכוונן את הצירים להשגת רווח אחיד. אם הצירים שחוקים — להחליפם. במקרה של מסגרת מעוותת — ליישר ולעגן מחדש.. עלות משוערת: ₪150-₪500 (ליחידה)', 'ת"י 1509 — רווח בין כנף למסגרת חייב להיות אחיד, בהתאם למפרט היצרן (בדרך כלל 3-5 מ"מ)', 'ת"י 1509 — רווח בין כנף למסגרת חייב להיות אחיד, בהתאם למפרט היצרן (בדרך כלל 3-5 מ"מ)', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת כניסה אלומיניום — בידוד אקוסטי לא מספיק** — דלת הכניסה לא מספקת בידוד אקוסטי מספיק — נשמעים רעשי חדר מדרגות, שכנים ומעלית בתוך הדירה. הפער בין הדלת למשקוף גדול מדי או חסרות גומיות איטום.. המלצה: להתקין/להחליף גומיות איטום היקפיות. להתקין סף תחתון אוטומטי (drop seal). אם לא מספיק — להחליף לדלת עם בידוד אקוסטי מוגבר.. עלות משוערת: ₪200-₪800 (ליחידה)', '**דלת כניסה אלומיניום — בידוד אקוסטי לא מספיק** — דלת הכניסה לא מספקת בידוד אקוסטי מספיק — נשמעים רעשי חדר מדרגות, שכנים ומעלית בתוך הדירה. הפער בין הדלת למשקוף גדול מדי או חסרות גומיות איטום.. המלצה: להתקין/להחליף גומיות איטום היקפיות. להתקין סף תחתון אוטומטי (drop seal). אם לא מספיק — להחליף לדלת עם בידוד אקוסטי מוגבר.. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1142 — נדרש בידוד אקוסטי מינימלי של 30 dB בין חדר מדרגות לדירה', 'ת"י 1142 — נדרש בידוד אקוסטי מינימלי של 30 dB בין חדר מדרגות לדירה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת מרפסת — חוסר מעקה בטיחות** — דלת מרפסת צרפתית (French door) ללא מעקה בטיחות חיצוני, כאשר פתח הדלת בקומה גבוהה ואין מרפסת. מהווה סכנת נפילה חמורה.. המלצה: להתקין מעקה בטיחות צמוד לפתח הדלת — מעקה אלומיניום/נירוסטה עם זכוכית בטיחות, בגובה 105 ס"מ.. עלות משוערת: ₪1500-₪4000 (למ"א)', '**דלת מרפסת — חוסר מעקה בטיחות** — דלת מרפסת צרפתית (French door) ללא מעקה בטיחות חיצוני, כאשר פתח הדלת בקומה גבוהה ואין מרפסת. מהווה סכנת נפילה חמורה.. המלצה: להתקין מעקה בטיחות צמוד לפתח הדלת — מעקה אלומיניום/נירוסטה עם זכוכית בטיחות, בגובה 105 ס"מ.. עלות משוערת: ₪1500-₪4000 (למ"א)', 'ת"י 1142 — פתח בקומה שנייה ומעלה חייב במעקה בגובה 105 ס"מ לפחות (עם דרישות רווח וחוזק)', 'ת"י 1142 — פתח בקומה שנייה ומעלה חייב במעקה בגובה 105 ס"מ לפחות (עם דרישות רווח וחוזק)', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס גלילה — מנוע חשמלי לא פועל** — מנוע התריס החשמלי לא פועל — התריס לא עולה, לא יורד, או נתקע באמצע. הגורמים: תקלת מנוע, בעיית חשמל, מתג מגבלה (limit switch) לא מכוונן, או קונדנסטור תקול.. המלצה: לבדוק חיבור חשמל ומפסק. לבדוק קונדנסטור מנוע. לכוונן מתגי מגבלה. אם המנוע שרוף — להחליף מנוע תואם למידות הגליל.. עלות משוערת: ₪400-₪1200 (ליחידה)', '**תריס גלילה — מנוע חשמלי לא פועל** — מנוע התריס החשמלי לא פועל — התריס לא עולה, לא יורד, או נתקע באמצע. הגורמים: תקלת מנוע, בעיית חשמל, מתג מגבלה (limit switch) לא מכוונן, או קונדנסטור תקול.. המלצה: לבדוק חיבור חשמל ומפסק. לבדוק קונדנסטור מנוע. לכוונן מתגי מגבלה. אם המנוע שרוף — להחליף מנוע תואם למידות הגליל.. עלות משוערת: ₪400-₪1200 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס גלילה — למלות (שלבים) עקומות או שבורות** — למלות (שלבים) של תריס הגלילה עקומות, שבורות, או מנותקות זו מזו. התריס לא יורד/עולה כראוי, לא אטום לאור, ומראה חיצוני פגום.. המלצה: להחליף את הלמלות הפגומות בלמלות חדשות תואמות (זהה ברוחב, עובי, וצורת חיבור). במקרה של נזק נרחב — להחליף את מילוי התריס כולו.. עלות משוערת: ₪200-₪800 (ליחידה)', '**תריס גלילה — למלות (שלבים) עקומות או שבורות** — למלות (שלבים) של תריס הגלילה עקומות, שבורות, או מנותקות זו מזו. התריס לא יורד/עולה כראוי, לא אטום לאור, ומראה חיצוני פגום.. המלצה: להחליף את הלמלות הפגומות בלמלות חדשות תואמות (זהה ברוחב, עובי, וצורת חיבור). במקרה של נזק נרחב — להחליף את מילוי התריס כולו.. עלות משוערת: ₪200-₪800 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס גלילה — מסילות צד פגומות** — מסילות הצד (מובילים) של תריס הגלילה פגומות, מעוותות, או לא מותקנות כראוי. התריס קופץ מהמסילה, נתקע, או לא מונע חדירת אור.. המלצה: ליישר את מסילות הצד ולעגן מחדש. אם פגומות — להחליף. לוודא רווח אחיד בין הלמלות למסילה.. עלות משוערת: ₪200-₪600 (ליחידה)', '**תריס גלילה — מסילות צד פגומות** — מסילות הצד (מובילים) של תריס הגלילה פגומות, מעוותות, או לא מותקנות כראוי. התריס קופץ מהמסילה, נתקע, או לא מונע חדירת אור.. המלצה: ליישר את מסילות הצד ולעגן מחדש. אם פגומות — להחליף. לוודא רווח אחיד בין הלמלות למסילה.. עלות משוערת: ₪200-₪600 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס גלילה — תיבת גלילה (קופסת תריס) לא מבודדת** — תיבת הגלילה (קופסת התריס) לא מבודדת תרמית ואקוסטית — נוצרת נקודת קור בחורף, עיבוי מים, חדירת רעש, ולעיתים גם חדירת מזיקים.. המלצה: לפתוח את תיבת הגלילה ולהדביק בידוד תרמי (לוח XPS/EPS או מוצר ייעודי). לאטום את כל הפרצים באיטום אלסטי.. עלות משוערת: ₪250-₪600 (ליחידה)', '**תריס גלילה — תיבת גלילה (קופסת תריס) לא מבודדת** — תיבת הגלילה (קופסת התריס) לא מבודדת תרמית ואקוסטית — נוצרת נקודת קור בחורף, עיבוי מים, חדירת רעש, ולעיתים גם חדירת מזיקים.. המלצה: לפתוח את תיבת הגלילה ולהדביק בידוד תרמי (לוח XPS/EPS או מוצר ייעודי). לאטום את כל הפרצים באיטום אלסטי.. עלות משוערת: ₪250-₪600 (ליחידה)', 'ת"י 1045 — תיבת תריס חייבת לעמוד בדרישות בידוד תרמי — ערך U מרבי כמו יתר המעטפת', 'ת"י 1045 — תיבת תריס חייבת לעמוד בדרישות בידוד תרמי — ערך U מרבי כמו יתר המעטפת', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס גלילה — רצועת הפעלה (סרט) קרועה או שחוקה** — רצועת ההפעלה (סרט התריס) של תריס ידני קרועה, שחוקה, או נתקעת בגליל. התריס לא ניתן להפעלה.. המלצה: להחליף את רצועת ההפעלה כולל גלגלת הסרט (avvolgitore). לוודא מידה תואמת (רוחב 14/20/23 מ"מ).. עלות משוערת: ₪100-₪300 (ליחידה)', '**תריס גלילה — רצועת הפעלה (סרט) קרועה או שחוקה** — רצועת ההפעלה (סרט התריס) של תריס ידני קרועה, שחוקה, או נתקעת בגליל. התריס לא ניתן להפעלה.. המלצה: להחליף את רצועת ההפעלה כולל גלגלת הסרט (avvolgitore). לוודא מידה תואמת (רוחב 14/20/23 מ"מ).. עלות משוערת: ₪100-₪300 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס גלילה — רעש חריג בזמן הפעלה** — התריס משמיע רעש חריג (חריקה, נקישות, רעידות) בזמן עלייה או ירידה. גורמים: מסילות יבשות, למלות פגומות, ציר לא מיושר, או מנוע רועד.. המלצה: לשמן מסילות צד בסיליקון ספריי. לבדוק ולהחליף למלות פגומות. לכוונן יישור גליל וציר. אם מנוע — לבדוק עיגון ושקטי רעידות.. עלות משוערת: ₪100-₪400 (ליחידה)', '**תריס גלילה — רעש חריג בזמן הפעלה** — התריס משמיע רעש חריג (חריקה, נקישות, רעידות) בזמן עלייה או ירידה. גורמים: מסילות יבשות, למלות פגומות, ציר לא מיושר, או מנוע רועד.. המלצה: לשמן מסילות צד בסיליקון ספריי. לבדוק ולהחליף למלות פגומות. לכוונן יישור גליל וציר. אם מנוע — לבדוק עיגון ושקטי רעידות.. עלות משוערת: ₪100-₪400 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס הצללה מתקפל — זרועות שבורות או רופפות** — זרועות תריס ההצללה המתקפל (תריס ונציאני/פרסול) שבורות, רופפות, או לא ננעלות במצב פתוח. התריס לא נשאר פתוח ברוח או לא נסגר כראוי.. המלצה: להחליף את הזרועות הפגומות בזרועות מקוריות. להדק את כל ברגי החיבור. לשמן צירים וציפים.. עלות משוערת: ₪200-₪700 (ליחידה)', '**תריס הצללה מתקפל — זרועות שבורות או רופפות** — זרועות תריס ההצללה המתקפל (תריס ונציאני/פרסול) שבורות, רופפות, או לא ננעלות במצב פתוח. התריס לא נשאר פתוח ברוח או לא נסגר כראוי.. המלצה: להחליף את הזרועות הפגומות בזרועות מקוריות. להדק את כל ברגי החיבור. לשמן צירים וציפים.. עלות משוערת: ₪200-₪700 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס גלילה — חדירת אור בין למלות במצב סגור** — כשהתריס סגור לחלוטין, נכנס אור בין הלמלות — הלמלות לא נסגרות ברצף צפוף, יש רווחים גלויים, או שלמלות מעוותות לא מתיישרות.. המלצה: לכוונן את מתח התריס ואת מגבלת הירידה. להחליף למלות מעוותות. לוודא שכל הלמלות מסוג זהה ותקינות.. עלות משוערת: ₪150-₪500 (ליחידה)', '**תריס גלילה — חדירת אור בין למלות במצב סגור** — כשהתריס סגור לחלוטין, נכנס אור בין הלמלות — הלמלות לא נסגרות ברצף צפוף, יש רווחים גלויים, או שלמלות מעוותות לא מתיישרות.. המלצה: לכוונן את מתח התריס ואת מגבלת הירידה. להחליף למלות מעוותות. לוודא שכל הלמלות מסוג זהה ותקינות.. עלות משוערת: ₪150-₪500 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — תריסים', '**תריס חשמלי תקוע / לא עולה** — תריס חשמלי שלא עולה, יורד, או תקוע באמצע.. המלצה: בדיקת מנוע, כוונון מסילות, החלפת רכיב פגום. עלות משוערת: ₪300-₪1000 (ליחידה)', '**תריס חשמלי תקוע / לא עולה** — תריס חשמלי שלא עולה, יורד, או תקוע באמצע.. המלצה: בדיקת מנוע, כוונון מסילות, החלפת רכיב פגום. עלות משוערת: ₪300-₪1000 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'זיגוג', '**חלון אלומיניום — זכוכית לא בטיחותית** — הותקנה זכוכית רגילה (לא בטיחותית) במקום שנדרשת זכוכית בטיחות — מחוסמת או שכבתית (למינציה). זכוכית רגילה מתנפצת לרסיסים חדים ומהווה סכנת חיים.. המלצה: להחליף את הזכוכית בזכוכית בטיחותית (מחוסמת או למינציה) בהתאם לדרישת התקן. לוודא חותמת תקן על הזכוכית החדשה.. עלות משוערת: ₪400-₪1200 (למ"ר)', '**חלון אלומיניום — זכוכית לא בטיחותית** — הותקנה זכוכית רגילה (לא בטיחותית) במקום שנדרשת זכוכית בטיחות — מחוסמת או שכבתית (למינציה). זכוכית רגילה מתנפצת לרסיסים חדים ומהווה סכנת חיים.. המלצה: להחליף את הזכוכית בזכוכית בטיחותית (מחוסמת או למינציה) בהתאם לדרישת התקן. לוודא חותמת תקן על הזכוכית החדשה.. עלות משוערת: ₪400-₪1200 (למ"ר)', 'ת"י 1099 — ת"י 1099 מחייב זכוכית בטיחות בחלונות עד גובה 80 ס"מ מהרצפה, בדלתות זכוכית, במעקות, ובמקלחות', 'ת"י 1099 — ת"י 1099 מחייב זכוכית בטיחות בחלונות עד גובה 80 ס"מ מהרצפה, בדלתות זכוכית, במעקות, ובמקלחות', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'זיגוג', '**חלון אלומיניום — זכוכית תרמית (דאבל גלייז) לא אטומה** — יחידת הזיגוג הכפול (דאבל גלייז) מאבדת את האטימות — נראית עננות/ערפל בין שכבות הזכוכית. סימן לכשל באיטום היקפי של היחידה, מה שמבטל את הבידוד התרמי.. המלצה: להחליף את יחידת הזיגוג הכפול בשלמותה. אין אפשרות לתקן יחידה שאיבדה אטימות.. עלות משוערת: ₪350-₪900 (למ"ר)', '**חלון אלומיניום — זכוכית תרמית (דאבל גלייז) לא אטומה** — יחידת הזיגוג הכפול (דאבל גלייז) מאבדת את האטימות — נראית עננות/ערפל בין שכבות הזכוכית. סימן לכשל באיטום היקפי של היחידה, מה שמבטל את הבידוד התרמי.. המלצה: להחליף את יחידת הזיגוג הכפול בשלמותה. אין אפשרות לתקן יחידה שאיבדה אטימות.. עלות משוערת: ₪350-₪900 (למ"ר)', 'ת"י 1509 — יחידת זיגוג מבודד חייבת לשמור על ריק/גז בין השכבות לאורך חיי המוצר', 'ת"י 1509 — יחידת זיגוג מבודד חייבת לשמור על ריק/גז בין השכבות לאורך חיי המוצר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'זיגוג', '**חלון אלומיניום — סדק או שבר בזכוכית** — סדק, שבר, או ניקוב בזכוכית החלון. יכול להיגרם ממכה, מתח תרמי, או מלחץ לא אחיד של מסגרת החלון על הזכוכית.. המלצה: להחליף את הזכוכית השבורה בזכוכית חדשה תואמת תקן (בטיחותית היכן שנדרש). לבדוק שהמסגרת לא לוחצת על הזכוכית.. עלות משוערת: ₪300-₪800 (למ"ר)', '**חלון אלומיניום — סדק או שבר בזכוכית** — סדק, שבר, או ניקוב בזכוכית החלון. יכול להיגרם ממכה, מתח תרמי, או מלחץ לא אחיד של מסגרת החלון על הזכוכית.. המלצה: להחליף את הזכוכית השבורה בזכוכית חדשה תואמת תקן (בטיחותית היכן שנדרש). לבדוק שהמסגרת לא לוחצת על הזכוכית.. עלות משוערת: ₪300-₪800 (למ"ר)', 'ת"י 1099 — זכוכית בחלון חייבת להיות שלמה, ללא סדקים או שברים, ולעמוד בדרישות בטיחות', 'ת"י 1099 — זכוכית בחלון חייבת להיות שלמה, ללא סדקים או שברים, ולעמוד בדרישות בטיחות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'זיגוג', '**זכוכית חלון — חוסר התאמה למפרט (עובי/סוג)** — הזכוכית שהותקנה לא תואמת למפרט המכר — עובי נמוך מהנדרש, זכוכית בודדת במקום כפולה, או חסרה שכבת Low-E שנדרשה במפרט.. המלצה: להחליף את הזכוכית בזכוכית התואמת למפרט המכר. לדרוש אישור יצרן על סוג הזכוכית שהותקנה.. עלות משוערת: ₪350-₪1000 (למ"ר)', '**זכוכית חלון — חוסר התאמה למפרט (עובי/סוג)** — הזכוכית שהותקנה לא תואמת למפרט המכר — עובי נמוך מהנדרש, זכוכית בודדת במקום כפולה, או חסרה שכבת Low-E שנדרשה במפרט.. המלצה: להחליף את הזכוכית בזכוכית התואמת למפרט המכר. לדרוש אישור יצרן על סוג הזכוכית שהותקנה.. עלות משוערת: ₪350-₪1000 (למ"ר)', 'ת"י 1509 — הזיגוג חייב להתאים למפרט הטכני של הפרויקט ולדרישות התקן לגודל החלון', 'ת"י 1509 — הזיגוג חייב להתאים למפרט הטכני של הפרויקט ולדרישות התקן לגודל החלון', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'זיגוג', '**חלון אלומיניום — חוסר בזכוכית Low-E נדרשת** — הותקנה זכוכית כפולה ללא שכבת Low-E (שכבה פולטת נמוכה) שנדרשת במפרט או לפי תקן בידוד תרמי. ללא Low-E הבידוד התרמי נמוך משמעותית.. המלצה: להחליף את יחידת הזיגוג הכפול ביחידה עם זכוכית Low-E. לוודא שסוג ה-Low-E (hard coat/soft coat) תואם למפרט.. עלות משוערת: ₪400-₪1000 (למ"ר)', '**חלון אלומיניום — חוסר בזכוכית Low-E נדרשת** — הותקנה זכוכית כפולה ללא שכבת Low-E (שכבה פולטת נמוכה) שנדרשת במפרט או לפי תקן בידוד תרמי. ללא Low-E הבידוד התרמי נמוך משמעותית.. המלצה: להחליף את יחידת הזיגוג הכפול ביחידה עם זכוכית Low-E. לוודא שסוג ה-Low-E (hard coat/soft coat) תואם למפרט.. עלות משוערת: ₪400-₪1000 (למ"ר)', 'ת"י 1045 — לעמידה בדרישות בידוד תרמי למבנים, נדרשת בדרך כלל זכוכית עם שכבת Low-E להשגת ערך U נמוך', 'ת"י 1045 — לעמידה בדרישות בידוד תרמי למבנים, נדרשת בדרך כלל זכוכית עם שכבת Low-E להשגת ערך U נמוך', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'זיגוג', '**זכוכית שרוטה / סדוקה** — שריטות או סדקים בזכוכית חלון.. המלצה: החלפת זכוכית פגומה. עלות משוערת: ₪300-₪1200 (ליחידה)', '**זכוכית שרוטה / סדוקה** — שריטות או סדקים בזכוכית חלון.. המלצה: החלפת זכוכית פגומה. עלות משוערת: ₪300-₪1200 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'פרזול ונעילה', '**חלון אלומיניום — ידית סיבובית רופפת או שבורה** — ידית החלון רופפת, מסתובבת ללא אחיזה, או שבורה. הידית לא מפעילה את מנגנון הנעילה כראוי והחלון נשאר לא נעול.. המלצה: להדק את בסיס הידית (להרים כיסוי פלסטיק ולהדק ברגים). אם הידית שבורה — להחליף בידית מקורית תואמת.. עלות משוערת: ₪80-₪250 (ליחידה)', '**חלון אלומיניום — ידית סיבובית רופפת או שבורה** — ידית החלון רופפת, מסתובבת ללא אחיזה, או שבורה. הידית לא מפעילה את מנגנון הנעילה כראוי והחלון נשאר לא נעול.. המלצה: להדק את בסיס הידית (להרים כיסוי פלסטיק ולהדק ברגים). אם הידית שבורה — להחליף בידית מקורית תואמת.. עלות משוערת: ₪80-₪250 (ליחידה)', 'ת"י 1509 — ידית החלון חייבת להפעיל את מנגנון הנעילה באופן מלא ובטוח בכל מצבי הפתיחה', 'ת"י 1509 — ידית החלון חייבת להפעיל את מנגנון הנעילה באופן מלא ובטוח בכל מצבי הפתיחה', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'פרזול ונעילה', '**חלון אלומיניום — נעילה לא תקינה (אספניולט)** — מנגנון הנעילה (אספניולט) לא נועל את החלון בכל נקודות הנעילה. חלק מנקודות הנעילה לא מתיישבות כראוי בנגד (striker plate) — החלון לא אטום ולא מאובטח.. המלצה: לכוונן את נקודות הנעילה והנגדים. לשמן את מנגנון האספניולט. אם פגום — להחליף את מוט הנעילה או הנגדים.. עלות משוערת: ₪150-₪450 (ליחידה)', '**חלון אלומיניום — נעילה לא תקינה (אספניולט)** — מנגנון הנעילה (אספניולט) לא נועל את החלון בכל נקודות הנעילה. חלק מנקודות הנעילה לא מתיישבות כראוי בנגד (striker plate) — החלון לא אטום ולא מאובטח.. המלצה: לכוונן את נקודות הנעילה והנגדים. לשמן את מנגנון האספניולט. אם פגום — להחליף את מוט הנעילה או הנגדים.. עלות משוערת: ₪150-₪450 (ליחידה)', 'ת"י 1509 — חלון חייב להינעל בכל נקודות הנעילה שתוכננו על ידי היצרן, עם לחיצה אחידה של הגומיות', 'ת"י 1509 — חלון חייב להינעל בכל נקודות הנעילה שתוכננו על ידי היצרן, עם לחיצה אחידה של הגומיות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'פרזול ונעילה', '**חלון אלומיניום — חוסר מגביל פתיחה בקומה גבוהה** — חלון בקומה 2 ומעלה חסר מגביל פתיחה (מגביל זווית או כבל בטיחות) בהתאם לתקנות הבטיחות. ילדים עלולים ליפול מחלון הנפתח לרווחה.. המלצה: להתקין מגביל פתיחה תקני — כבל בטיחות או מגביל זווית צמוד פרופיל — בכל חלון נדרש. לוודא שהמגביל ניתן לשחרור על ידי מבוגר בלבד.. עלות משוערת: ₪120-₪350 (ליחידה)', '**חלון אלומיניום — חוסר מגביל פתיחה בקומה גבוהה** — חלון בקומה 2 ומעלה חסר מגביל פתיחה (מגביל זווית או כבל בטיחות) בהתאם לתקנות הבטיחות. ילדים עלולים ליפול מחלון הנפתח לרווחה.. המלצה: להתקין מגביל פתיחה תקני — כבל בטיחות או מגביל זווית צמוד פרופיל — בכל חלון נדרש. לוודא שהמגביל ניתן לשחרור על ידי מבוגר בלבד.. עלות משוערת: ₪120-₪350 (ליחידה)', 'ת"י 1509 — חלון מעל קומת קרקע חייב לכלול מגביל פתיחה המגביל את הפתח ל-100 מ"מ מרבי, עם אפשרות שחרור למבוגרים', 'ת"י 1509 — חלון מעל קומת קרקע חייב לכלול מגביל פתיחה המגביל את הפתח ל-100 מ"מ מרבי, עם אפשרות שחרור למבוגרים', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'פרזול ונעילה', '**חלון אלומיניום — חוסר סורג בטיחות בחלון נמוך** — חלון שתחתיתו בגובה נמוך מ-80 ס"מ מהרצפה חסר סורג בטיחות או מעקה להגנה מפני נפילה, בעיקר בקומות גבוהות.. המלצה: להתקין סורג בטיחות פנימי (מפרופיל אלומיניום או נירוסטה) בהתאם לתקן, עם רווח מרבי של 10 ס"מ בין חלקיו.. עלות משוערת: ₪400-₪1200 (ליחידה)', '**חלון אלומיניום — חוסר סורג בטיחות בחלון נמוך** — חלון שתחתיתו בגובה נמוך מ-80 ס"מ מהרצפה חסר סורג בטיחות או מעקה להגנה מפני נפילה, בעיקר בקומות גבוהות.. המלצה: להתקין סורג בטיחות פנימי (מפרופיל אלומיניום או נירוסטה) בהתאם לתקן, עם רווח מרבי של 10 ס"מ בין חלקיו.. עלות משוערת: ₪400-₪1200 (ליחידה)', 'ת"י 1142 — נדרש אמצעי מיגון (סורג/מעקה) בחלון שתחתיתו נמוכה מ-80 ס"מ מרצפת החדר, בקומה שנייה ומעלה', 'ת"י 1142 — נדרש אמצעי מיגון (סורג/מעקה) בחלון שתחתיתו נמוכה מ-80 ס"מ מרצפת החדר, בקומה שנייה ומעלה', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'פרזול ונעילה', '**חלון אלומיניום — פרזול (Hardware) לא תואם למפרט** — הפרזול שהותקן (ידיות, צירים, מנגנוני נעילה) אינו תואם למפרט הפרויקט — דרגה נמוכה יותר, יצרן אחר, או חסרים רכיבים שנדרשו (כגון נעילת ביטחון).. המלצה: להחליף את הפרזול בפרזול התואם למפרט המכר. לתעד את ההבדל ולדרוש התאמה או פיצוי.. עלות משוערת: ₪200-₪800 (ליחידה)', '**חלון אלומיניום — פרזול (Hardware) לא תואם למפרט** — הפרזול שהותקן (ידיות, צירים, מנגנוני נעילה) אינו תואם למפרט הפרויקט — דרגה נמוכה יותר, יצרן אחר, או חסרים רכיבים שנדרשו (כגון נעילת ביטחון).. המלצה: להחליף את הפרזול בפרזול התואם למפרט המכר. לתעד את ההבדל ולדרוש התאמה או פיצוי.. עלות משוערת: ₪200-₪800 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'פרזול ונעילה', '**ידית חלון שבורה / רופפת** — ידית חלון שבורה, רופפת, או לא נועלת.. המלצה: החלפת ידית חלון. עלות משוערת: ₪80-₪250 (ליחידה)', '**ידית חלון שבורה / רופפת** — ידית חלון שבורה, רופפת, או לא נועלת.. המלצה: החלפת ידית חלון. עלות משוערת: ₪80-₪250 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**שקע חשמל ללא הארקה תקינה** — שקע חשמל שאינו מחובר להארקה או שחיבור ההארקה לקוי. מדידה מראה התנגדות הארקה גבוהה מהמותר (מעל 1 אוהם). מהווה סכנת חשמול.. המלצה: בדיקת חיבור מוליך הארקה בשקע ובלוח החשמל, תיקון או החלפת החיבור הלקוי. עלות משוערת: ₪150-₪350 (ליחידה)', '**שקע חשמל ללא הארקה תקינה** — שקע חשמל שאינו מחובר להארקה או שחיבור ההארקה לקוי. מדידה מראה התנגדות הארקה גבוהה מהמותר (מעל 1 אוהם). מהווה סכנת חשמול.. המלצה: בדיקת חיבור מוליך הארקה בשקע ובלוח החשמל, תיקון או החלפת החיבור הלקוי. עלות משוערת: ₪150-₪350 (ליחידה)', 'ת"י 61 — כל שקע חשמל חייב להיות מחובר למוליך הארקה רציף עם התנגדות שאינה עולה על 1 אוהם', 'ת"י 61 — כל שקע חשמל חייב להיות מחובר למוליך הארקה רציף עם התנגדות שאינה עולה על 1 אוהם', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**שקע חשמל בחדר רחצה במרחק לא תקני מנקודת מים** — שקע חשמל מותקן בתוך אזור 1 או אזור 2 של חדר הרחצה (פחות מ-60 ס"מ ממקור מים), בניגוד לתקנות. סכנת חשמול בסביבה רטובה.. המלצה: העתקת השקע למיקום תקני באזור 3, מרחק מינימלי 60 ס"מ מנקודת מים, עם הגנת RCD. עלות משוערת: ₪400-₪800 (ליחידה)', '**שקע חשמל בחדר רחצה במרחק לא תקני מנקודת מים** — שקע חשמל מותקן בתוך אזור 1 או אזור 2 של חדר הרחצה (פחות מ-60 ס"מ ממקור מים), בניגוד לתקנות. סכנת חשמול בסביבה רטובה.. המלצה: העתקת השקע למיקום תקני באזור 3, מרחק מינימלי 60 ס"מ מנקודת מים, עם הגנת RCD. עלות משוערת: ₪400-₪800 (ליחידה)', 'ת"י 61 — שקעים בחדר רחצה חייבים להיות מותקנים באזור 3 בלבד, במרחק מינימלי של 60 ס"מ מגבול האמבטיה או המקלחון', 'ת"י 61 — שקעים בחדר רחצה חייבים להיות מותקנים באזור 3 בלבד, במרחק מינימלי של 60 ס"מ מגבול האמבטיה או המקלחון', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**חסר מפסק פחת (RCD) בלוח החשמל** — לוח החשמל הדירתי חסר מפסק פחת (RCD) בזרם דלף 30mA על מעגלי שקעים. מפסק פחת נדרש להגנה מפני חשמול.. המלצה: התקנת מפסק פחת RCD 30mA בלוח החשמל על כל מעגלי השקעים. עלות משוערת: ₪350-₪700 (ליחידה)', '**חסר מפסק פחת (RCD) בלוח החשמל** — לוח החשמל הדירתי חסר מפסק פחת (RCD) בזרם דלף 30mA על מעגלי שקעים. מפסק פחת נדרש להגנה מפני חשמול.. המלצה: התקנת מפסק פחת RCD 30mA בלוח החשמל על כל מעגלי השקעים. עלות משוערת: ₪350-₪700 (ליחידה)', 'ת"י 61 — כל מעגלי השקעים בדירה חייבים להיות מוגנים במפסק פחת (RCD) בזרם דלף מקסימלי של 30mA', 'ת"י 61 — כל מעגלי השקעים בדירה חייבים להיות מוגנים במפסק פחת (RCD) בזרם דלף מקסימלי של 30mA', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**מפסק פחת (RCD) לא מתפקד** — מפסק הפחת מותקן אך אינו מנתק את המעגל בלחיצה על כפתור הבדיקה (TEST). המפסק עלול להיות תקול ולא לספק הגנה מפני חשמול.. המלצה: החלפת מפסק הפחת התקול במפסק חדש תקין ובדיקת תקינות כל מפסקי הפחת בלוח. עלות משוערת: ₪250-₪500 (ליחידה)', '**מפסק פחת (RCD) לא מתפקד** — מפסק הפחת מותקן אך אינו מנתק את המעגל בלחיצה על כפתור הבדיקה (TEST). המפסק עלול להיות תקול ולא לספק הגנה מפני חשמול.. המלצה: החלפת מפסק הפחת התקול במפסק חדש תקין ובדיקת תקינות כל מפסקי הפחת בלוח. עלות משוערת: ₪250-₪500 (ליחידה)', 'ת"י 61 — מפסק פחת חייב לנתק את המעגל תוך 300 אלפיות שנייה בזרם דלף של 30mA, ולעבור בדיקה תקופתית', 'ת"י 61 — מפסק פחת חייב לנתק את המעגל תוך 300 אלפיות שנייה בזרם דלף של 30mA, ולעבור בדיקה תקופתית', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**לוח חשמל ללא סימון מעגלים** — מפסקים בלוח החשמל אינם מסומנים בזיהוי המעגל שהם מגנים עליו. מקשה על איתור תקלות ועל ניתוק חירום.. המלצה: סימון כל מפסקי הלוח בתוויות ברורות המציינות את המעגל המוגן (חדר/מכשיר). עלות משוערת: ₪100-₪200 (ליחידה)', '**לוח חשמל ללא סימון מעגלים** — מפסקים בלוח החשמל אינם מסומנים בזיהוי המעגל שהם מגנים עליו. מקשה על איתור תקלות ועל ניתוק חירום.. המלצה: סימון כל מפסקי הלוח בתוויות ברורות המציינות את המעגל המוגן (חדר/מכשיר). עלות משוערת: ₪100-₪200 (ליחידה)', 'ת"י 61 — כל מפסק בלוח חשמל חייב להיות מסומן בבירור לזיהוי המעגל המוגן', 'ת"י 61 — כל מפסק בלוח חשמל חייב להיות מסומן בבירור לזיהוי המעגל המוגן', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**לוח חשמל ללא דלת או מכסה** — לוח החשמל הדירתי חסר דלת או מכסה, חלקים חיים חשופים. סכנת חשמול במיוחד לילדים.. המלצה: התקנת דלת/מכסה מקורי ללוח החשמל עם נעילה תקנית. עלות משוערת: ₪200-₪500 (ליחידה)', '**לוח חשמל ללא דלת או מכסה** — לוח החשמל הדירתי חסר דלת או מכסה, חלקים חיים חשופים. סכנת חשמול במיוחד לילדים.. המלצה: התקנת דלת/מכסה מקורי ללוח החשמל עם נעילה תקנית. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 61 — לוח חשמל חייב להיות מכוסה בדלת או מכסה המונע גישה לחלקים חיים ללא כלי עזר', 'ת"י 61 — לוח חשמל חייב להיות מכוסה בדלת או מכסה המונע גישה לחלקים חיים ללא כלי עזר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**שקע חשמל רופף או יוצא מהקיר** — שקע חשמל אינו מחוזק כראוי לקופסת החשמל בקיר, נע או יוצא החוצה בעת הוצאת תקע. עלול לחשוף חיבורים חשמליים.. המלצה: חיזוק השקע לקופסת החשמל בברגים, החלפת קופסה שבורה במידת הצורך. עלות משוערת: ₪80-₪200 (ליחידה)', '**שקע חשמל רופף או יוצא מהקיר** — שקע חשמל אינו מחוזק כראוי לקופסת החשמל בקיר, נע או יוצא החוצה בעת הוצאת תקע. עלול לחשוף חיבורים חשמליים.. המלצה: חיזוק השקע לקופסת החשמל בברגים, החלפת קופסה שבורה במידת הצורך. עלות משוערת: ₪80-₪200 (ליחידה)', 'ת"י 61 — כל אביזר חשמלי חייב להיות מחוזק היטב לקופסת ההתקנה ולהיות יציב', 'ת"י 61 — כל אביזר חשמלי חייב להיות מחוזק היטב לקופסת ההתקנה ולהיות יציב', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**חוסר בשקעי חשמל בחדר לפי תקן** — מספר שקעי החשמל בחדר נמוך מהנדרש בתקן. לדוגמה: מטבח עם פחות מ-6 שקעים, או חדר שינה עם פחות מ-3 שקעים.. המלצה: הוספת שקעי חשמל בהתאם לדרישות התקן עבור ייעוד החדר. עלות משוערת: ₪300-₪600 (ליחידה)', '**חוסר בשקעי חשמל בחדר לפי תקן** — מספר שקעי החשמל בחדר נמוך מהנדרש בתקן. לדוגמה: מטבח עם פחות מ-6 שקעים, או חדר שינה עם פחות מ-3 שקעים.. המלצה: הוספת שקעי חשמל בהתאם לדרישות התקן עבור ייעוד החדר. עלות משוערת: ₪300-₪600 (ליחידה)', 'ת"י 61 — מספר מינימלי של שקעים לפי ייעוד החדר: מטבח 6, סלון 5, חדר שינה 3, חדר רחצה 1', 'ת"י 61 — מספר מינימלי של שקעים לפי ייעוד החדר: מטבח 6, סלון 5, חדר שינה 3, חדר רחצה 1', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**גובה שקע חשמל לא תקני** — שקע חשמל מותקן בגובה שאינו עומד בדרישות התקן. שקעים רגילים צריכים להיות בגובה 40-50 ס"מ מהרצפה, שקעי מטבח בגובה 110-120 ס"מ.. המלצה: העתקת השקע לגובה התקני בהתאם לייעוד החדר. עלות משוערת: ₪300-₪600 (ליחידה)', '**גובה שקע חשמל לא תקני** — שקע חשמל מותקן בגובה שאינו עומד בדרישות התקן. שקעים רגילים צריכים להיות בגובה 40-50 ס"מ מהרצפה, שקעי מטבח בגובה 110-120 ס"מ.. המלצה: העתקת השקע לגובה התקני בהתאם לייעוד החדר. עלות משוערת: ₪300-₪600 (ליחידה)', 'ת"י 61 — גובה התקנת שקעים: רגיל 40-50 ס"מ, מטבח 110-120 ס"מ מעל הרצפה הגמורה', 'ת"י 61 — גובה התקנת שקעים: רגיל 40-50 ס"מ, מטבח 110-120 ס"מ מעל הרצפה הגמורה', true, 'low');
