INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**חסרה נקודת תאורה בחדר** — חדר ללא נקודת תאורה בתקרה או בקיר, בניגוד לדרישות התקן. כל חדר מגורים חייב לכלול לפחות נקודת תאורה אחת.. המלצה: התקנת נקודת תאורה בתקרה עם מתג הפעלה בכניסה לחדר. עלות משוערת: ₪400-₪800 (ליחידה)', '**חסרה נקודת תאורה בחדר** — חדר ללא נקודת תאורה בתקרה או בקיר, בניגוד לדרישות התקן. כל חדר מגורים חייב לכלול לפחות נקודת תאורה אחת.. המלצה: התקנת נקודת תאורה בתקרה עם מתג הפעלה בכניסה לחדר. עלות משוערת: ₪400-₪800 (ליחידה)', 'ת"י 61 — כל חדר חייב לכלול לפחות נקודת תאורה אחת מחוברת למתג', 'ת"י 61 — כל חדר חייב לכלול לפחות נקודת תאורה אחת מחוברת למתג', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**כבלים חשמליים חשופים ללא הגנה** — כבלים חשמליים גלויים ללא צנרת הגנה או כיסוי מתאים. הכבלים חשופים לנזק מכני ולסכנת חשמול.. המלצה: התקנת צנרת הגנה (PVC או מתכת) לכיסוי הכבלים החשופים. עלות משוערת: ₪150-₪400 (למ"א)', '**כבלים חשמליים חשופים ללא הגנה** — כבלים חשמליים גלויים ללא צנרת הגנה או כיסוי מתאים. הכבלים חשופים לנזק מכני ולסכנת חשמול.. המלצה: התקנת צנרת הגנה (PVC או מתכת) לכיסוי הכבלים החשופים. עלות משוערת: ₪150-₪400 (למ"א)', 'ת"י 61 — כבלים חשמליים חייבים לעבור בצנרת הגנה או להיות מוגנים מפני נזק מכני', 'ת"י 61 — כבלים חשמליים חייבים לעבור בצנרת הגנה או להיות מוגנים מפני נזק מכני', true, 'medium');
