INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**קופסת חשמל ללא מכסה** — קופסת חיבור/הסתעפות חשמלית ללא מכסה, חיבורים חשמליים חשופים. סכנת חשמול ונזק מלחות או אבק.. המלצה: התקנת מכסה תקני לקופסת החשמל. עלות משוערת: ₪30-₪80 (ליחידה)', '**קופסת חשמל ללא מכסה** — קופסת חיבור/הסתעפות חשמלית ללא מכסה, חיבורים חשמליים חשופים. סכנת חשמול ונזק מלחות או אבק.. המלצה: התקנת מכסה תקני לקופסת החשמל. עלות משוערת: ₪30-₪80 (ליחידה)', 'ת"י 61 — כל קופסת חיבור חייבת להיות מכוסה במכסה מתאים', 'ת"י 61 — כל קופסת חיבור חייבת להיות מכוסה במכסה מתאים', true, 'medium');
