INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**לוח חשמל עמוס - אין מקום למעגלים נוספים** — לוח החשמל הדירתי מלא לחלוטין ללא מודולים פנויים להרחבה עתידית. מקשה על הוספת מעגלים ועלול לגרום לחיבורים לא תקניים.. המלצה: החלפת הלוח בלוח גדול יותר עם מקום להרחבה, או פיצול למספר לוחות. עלות משוערת: ₪1500-₪3500 (ליחידה)', '**לוח חשמל עמוס - אין מקום למעגלים נוספים** — לוח החשמל הדירתי מלא לחלוטין ללא מודולים פנויים להרחבה עתידית. מקשה על הוספת מעגלים ועלול לגרום לחיבורים לא תקניים.. המלצה: החלפת הלוח בלוח גדול יותר עם מקום להרחבה, או פיצול למספר לוחות. עלות משוערת: ₪1500-₪3500 (ליחידה)', 'ת"י 61 — לוח חשמל דירתי חייב לכלול לפחות 20% מקום פנוי להרחבה עתידית', 'ת"י 61 — לוח חשמל דירתי חייב לכלול לפחות 20% מקום פנוי להרחבה עתידית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**שקע חשמל מטבח ללא הגנת RCD ייעודית** — שקעי חשמל במטבח (משטח עבודה) אינם מוגנים במפסק פחת ייעודי. אזור רטוב הדורש הגנה מוגברת.. המלצה: התקנת מפסק פחת RCD 30mA ייעודי למעגלי שקעי המטבח. עלות משוערת: ₪300-₪600 (ליחידה)', '**שקע חשמל מטבח ללא הגנת RCD ייעודית** — שקעי חשמל במטבח (משטח עבודה) אינם מוגנים במפסק פחת ייעודי. אזור רטוב הדורש הגנה מוגברת.. המלצה: התקנת מפסק פחת RCD 30mA ייעודי למעגלי שקעי המטבח. עלות משוערת: ₪300-₪600 (ליחידה)', 'ת"י 61 — שקעים באזורים רטובים (מטבח, חדר כביסה) חייבים הגנת RCD 30mA', 'ת"י 61 — שקעים באזורים רטובים (מטבח, חדר כביסה) חייבים הגנת RCD 30mA', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**חוסר התאמה בין פאזות בלוח חשמל תלת-פאזי** — חלוקת עומסים לא מאוזנת בין שלוש הפאזות בלוח חשמל תלת-פאזי. גורם לעומס יתר על פאזה אחת ולירידת מתח.. המלצה: איזון מחדש של חלוקת המעגלים בין הפאזות בלוח החשמל. עלות משוערת: ₪300-₪600 (ליחידה)', '**חוסר התאמה בין פאזות בלוח חשמל תלת-פאזי** — חלוקת עומסים לא מאוזנת בין שלוש הפאזות בלוח חשמל תלת-פאזי. גורם לעומס יתר על פאזה אחת ולירידת מתח.. המלצה: איזון מחדש של חלוקת המעגלים בין הפאזות בלוח החשמל. עלות משוערת: ₪300-₪600 (ליחידה)', 'ת"י 61 — עומסים בלוח תלת-פאזי חייבים להיות מאוזנים בין הפאזות, סטייה מקסימלית 20%', 'ת"י 61 — עומסים בלוח תלת-פאזי חייבים להיות מאוזנים בין הפאזות, סטייה מקסימלית 20%', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**תאורת חירום חסרה בחדר מדרגות** — חדר מדרגות ללא תאורת חירום עצמאית עם סוללה. בעת הפסקת חשמל חדר המדרגות חשוך לחלוטין, סכנת נפילה.. המלצה: התקנת גוף תאורת חירום עם סוללה בכל קומה בחדר המדרגות. עלות משוערת: ₪250-₪500 (ליחידה)', '**תאורת חירום חסרה בחדר מדרגות** — חדר מדרגות ללא תאורת חירום עצמאית עם סוללה. בעת הפסקת חשמל חדר המדרגות חשוך לחלוטין, סכנת נפילה.. המלצה: התקנת גוף תאורת חירום עם סוללה בכל קומה בחדר המדרגות. עלות משוערת: ₪250-₪500 (ליחידה)', 'ת"י 61 — חדרי מדרגות ומסדרונות חייבים בתאורת חירום עם סוללת גיבוי לשעה לפחות', 'ת"י 61 — חדרי מדרגות ומסדרונות חייבים בתאורת חירום עם סוללת גיבוי לשעה לפחות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**שקע חשמל חיצוני ללא דרגת הגנה IP מתאימה** — שקע חשמל במרפסת או בחוץ ללא דרגת הגנה IP44 לפחות. חשוף לרטיבות ולגשם.. המלצה: החלפת השקע בשקע עם דרגת הגנה IP44 ומכסה קפיצי. עלות משוערת: ₪150-₪350 (ליחידה)', '**שקע חשמל חיצוני ללא דרגת הגנה IP מתאימה** — שקע חשמל במרפסת או בחוץ ללא דרגת הגנה IP44 לפחות. חשוף לרטיבות ולגשם.. המלצה: החלפת השקע בשקע עם דרגת הגנה IP44 ומכסה קפיצי. עלות משוערת: ₪150-₪350 (ליחידה)', 'ת"י 61 — שקעים חיצוניים חייבים בדרגת הגנה IP44 לפחות עם מכסה קפיצי', 'ת"י 61 — שקעים חיצוניים חייבים בדרגת הגנה IP44 לפחות עם מכסה קפיצי', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**פס שוואה (אפס) לקוי בלוח חשמל** — פס השוואה (Neutral bar) בלוח החשמל עם חיבורים רופפים, חמצון, או עומס יתר. גורם לתקלות זרם ולסכנת שריפה.. המלצה: ניקוי פס השוואה, הידוק כל החיבורים, החלפת פס פגום במידת הצורך. עלות משוערת: ₪200-₪400 (ליחידה)', '**פס שוואה (אפס) לקוי בלוח חשמל** — פס השוואה (Neutral bar) בלוח החשמל עם חיבורים רופפים, חמצון, או עומס יתר. גורם לתקלות זרם ולסכנת שריפה.. המלצה: ניקוי פס השוואה, הידוק כל החיבורים, החלפת פס פגום במידת הצורך. עלות משוערת: ₪200-₪400 (ליחידה)', 'ת"י 61 — פס האפס חייב להיות מחובר היטב עם כל מוליכי האפס מהודקים בברגים', 'ת"י 61 — פס האפס חייב להיות מחובר היטב עם כל מוליכי האפס מהודקים בברגים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**חיווט חשמל בממ"ד לא בצנרת שריון** — חיווט חשמל בתוך חדר הממ"ד שאינו עובר בצנרת שריון (ממ"ד דורש צנרת מוגנת). בפגיעה ישירה הכבלים עלולים להינזק.. המלצה: החלפת הצנרת הקיימת בצנרת שריון מתאימה לממ"ד. עלות משוערת: ₪500-₪1200 (ליחידה)', '**חיווט חשמל בממ"ד לא בצנרת שריון** — חיווט חשמל בתוך חדר הממ"ד שאינו עובר בצנרת שריון (ממ"ד דורש צנרת מוגנת). בפגיעה ישירה הכבלים עלולים להינזק.. המלצה: החלפת הצנרת הקיימת בצנרת שריון מתאימה לממ"ד. עלות משוערת: ₪500-₪1200 (ליחידה)', 'ת"י 4766 — כבילה חשמלית בממ"ד חייבת לעבור בצנרת שריון מוגנת', 'ת"י 4766 — כבילה חשמלית בממ"ד חייבת לעבור בצנרת שריון מוגנת', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חשמל', '**שקע חשמל במרפסת שירות ללא הגנת מים** — שקע חשמל במרפסת שירות (כביסה) ללא כיסוי עמיד מים. מרפסת שירות חשופה לרטיבות ולמים.. המלצה: החלפת השקע בדגם IP44 עם מכסה קפיצי, וודא הגנת RCD על המעגל. עלות משוערת: ₪200-₪400 (ליחידה)', '**שקע חשמל במרפסת שירות ללא הגנת מים** — שקע חשמל במרפסת שירות (כביסה) ללא כיסוי עמיד מים. מרפסת שירות חשופה לרטיבות ולמים.. המלצה: החלפת השקע בדגם IP44 עם מכסה קפיצי, וודא הגנת RCD על המעגל. עלות משוערת: ₪200-₪400 (ליחידה)', 'ת"י 61 — שקעים בסביבה רטובה/חיצונית חייבים בדרגת הגנה IP44 ומפסק פחת RCD', 'ת"י 61 — שקעים בסביבה רטובה/חיצונית חייבים בדרגת הגנה IP44 ומפסק פחת RCD', true, 'medium');
